          </div>
          <div>
            <div className="flex items-center justify-between pl-1 mb-1">
              <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.broughtForward}</label>
              <button 
                type="button" 
                onClick={() => setIsManualMode(!isManualMode)}
                className="flex items-center gap-1 text-[10px] font-black text-indigo-500 hover:text-indigo-600 transition-colors uppercase tracking-tight"
