                    : 'border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 text-slate-400 dark:text-slate-600'
                }`}
                value={formData.broughtForward === '' ? '' : formData.broughtForward}
                onChange={handleChange}
