import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';
import { AlertCircle, RefreshCw, BadgeAlert } from 'lucide-react';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  getStartingBalance: (date: string) => number;
  onSubmit: (data: Transaction) => void;
  formatCurrency: (amount: number) => string;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, getStartingBalance, onSubmit, formatCurrency }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    electricity: '' as any,
    water: '' as any,
    travel: '' as any,
    compoundInvestment: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  const [dateError, setDateError] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        electricity: initialData.electricity || '',
        water: initialData.water || '',
        travel: initialData.travel || '',
        compoundInvestment: initialData.compoundInvestment || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward,
      });
    } else {
      setIsSyncing(true);
      const bf = getStartingBalance(formData.date);
      setFormData(prev => ({
        ...prev,
        broughtForward: Number(bf) || 0
      }));
      setTimeout(() => setIsSyncing(false), 400);
    }
  }, [initialData, getStartingBalance, formData.date]);

  const validateDate = (dateString: string) => {
    const selectedDate = new Date(dateString);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    selectedDate.setHours(0, 0, 0, 0);

    if (selectedDate > today) {
      setDateError(t.futureDateError);
      return false;
    } else {
      setDateError(null);
      return true;
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    if (name === 'date') validateDate(value);

    let val = value;
    if (type === 'number' && Number(value) < 0) {
      val = '0';
    }

    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (val === '' ? '' : Number(val)) : val
    }));
  };

  const val = (v: any) => {
    const n = Number(v);
    return isNaN(n) ? 0 : n;
  };

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.electricity) +
    val(formData.water) +
    val(formData.travel) +
    val(formData.compoundInvestment) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateDate(formData.date)) return;

    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      electricity: val(formData.electricity),
      water: val(formData.water),
      travel: val(formData.travel),
      compoundInvestment: val(formData.compoundInvestment),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses: totalExpenses,
      totalBalance: totalBalance,
      timestamp: initialData?.timestamp || new Date().toISOString()
    });
  };

  return (
    <div className="space-y-6">
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1 mb-1">{t.date}</label>
            <input
              type="date"
              name="date"
              required
              className={`w-full px-4 py-3 rounded-2xl border ${dateError ? 'border-rose-500 ring-2 ring-rose-500/20' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-sm`}
              value={formData.date}
              onChange={handleChange}
            />
            {dateError && (
              <div className="flex items-center gap-1.5 text-rose-500 text-[10px] font-black uppercase tracking-tight pl-1 pt-1 animate-in fade-in slide-in-from-top-1">
                <AlertCircle className="w-3.5 h-3.5" />
                {dateError}
              </div>
            )}
          </div>
          <div className="space-y-1">
            <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1 mb-1">
              {t.broughtForward}
            </label>
            <div className="relative group">
              <input
                type="number"
                name="broughtForward"
                placeholder="0"
                className={`w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/50 text-indigo-600 dark:text-indigo-400 transition-all focus:ring-2 focus:ring-indigo-500 outline-none font-black text-sm ${isSyncing ? 'animate-pulse' : ''}`}
                value={formData.broughtForward === '' ? '' : formData.broughtForward}
                onChange={handleChange}
              />
              <div className="flex items-center gap-1 mt-1 pl-1">
                {isSyncing ? (
                  <RefreshCw className="w-2.5 h-2.5 text-indigo-400 animate-spin" />
                ) : (
                  <BadgeAlert className="w-2.5 h-2.5 text-slate-300" />
                )}
                <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-tighter">
                  {isSyncing ? 'Recalculating sequence...' : 'Synced from previous day'}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <div>
            <label className="block text-xs font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest pl-1 mb-1">{t.dailyCash}</label>
            <input
              type="number"
              name="dailyCash"
              placeholder="0"
              min="0"
              className="w-full px-4 py-3 rounded-2xl border border-emerald-100 dark:border-emerald-900 bg-emerald-50/30 dark:bg-emerald-900/10 font-black text-emerald-800 dark:text-emerald-200 transition-all focus:ring-2 focus:ring-emerald-500 outline-none"
              value={formData.dailyCash === '' ? '' : formData.dailyCash}
              onChange={handleChange}
            />
          </div>
          {[
            { name: 'groceries', label: t.groceries },
            { name: 'vegetables', label: t.vegetables },
            { name: 'fishEgg', label: t.fishEgg },
            { name: 'chicken', label: t.chicken },
            { name: 'houseRent', label: t.houseRent },
            { name: 'electricity', label: t.electricity },
            { name: 'water', label: t.water },
            { name: 'travel', label: t.travel },
            { name: 'compoundInvestment', label: t.compoundInvestment },
            { name: 'others', label: t.others },
          ].map(field => (
            <div key={field.name}>
              <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1 mb-1">{field.label}</label>
              <input
                type="number"
                name={field.name}
                placeholder="0"
                min="0"
                className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 transition-all focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                value={(formData as any)[field.name] === '' ? '' : (formData as any)[field.name]}
                onChange={handleChange}
              />
            </div>
          ))}
        </div>

        <div className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-3xl flex flex-wrap gap-12 items-center justify-center border border-slate-100 dark:border-slate-800 transition-colors shadow-inner">
          <div className="text-center group">
            <p className="text-[10px] text-slate-400 dark:text-slate-500 uppercase tracking-widest font-black mb-2 group-hover:text-rose-400 transition-colors">{t.totalExpenses}</p>
            <p className="text-3xl font-black text-rose-600 dark:text-rose-500">{formatCurrency(totalExpenses)}</p>
          </div>
          <div className="w-px h-12 bg-slate-200 dark:bg-slate-700 hidden sm:block" />
          <div className="text-center group">
            <p className="text-[10px] text-slate-400 dark:text-slate-500 uppercase tracking-widest font-black mb-2 group-hover:text-indigo-400 transition-colors">{t.totalBalance}</p>
            <p className="text-3xl font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(totalBalance)}</p>
          </div>
        </div>

        <button
          type="submit"
          disabled={!!dateError}
          className={`w-full ${dateError ? 'bg-slate-200 cursor-not-allowed opacity-50' : 'bg-indigo-600 hover:bg-indigo-700 shadow-xl shadow-indigo-100 dark:shadow-none'} text-white py-5 rounded-3xl font-black text-sm uppercase tracking-widest active:scale-[0.99] transition-all`}
        >
          {t.save}
        </button>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useMemo, useCallback } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter, PieChart, AlertCircle, TrendingDown } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  budgets?: MonthlyBudget[];
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions = [], onEdit, onDelete, isLoading, formatCurrency, budgets = [] }) => {
  const [stagedSearch, setStagedSearch] = useState('');
  const [stagedStart, setStagedStart] = useState('');
  const [stagedEnd, setStagedEnd] = useState('');

  const [activeSearch, setActiveSearch] = useState('');
  const [activeStart, setActiveStart] = useState('');
  const [activeEnd, setActiveEnd] = useState('');

  const handleApplyFilters = useCallback((e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }
    setActiveSearch(stagedSearch);
    setActiveStart(stagedStart);
    setActiveEnd(stagedEnd);
  }, [stagedSearch, stagedStart, stagedEnd]);

  const hasPendingFilters = stagedSearch !== activeSearch || stagedStart !== activeStart || stagedEnd !== activeEnd;

  const filteredTransactions = useMemo(() => {
    const lowerSearch = activeSearch.toLowerCase().trim();
    const source = (activeSearch || activeStart || activeEnd) ? allTransactions : transactions;

    return source.filter(tx => {
      if (activeStart && tx.date < activeStart) return false;
      if (activeEnd && tx.date > activeEnd) return false;

      if (lowerSearch) {
        const formattedDate = tx.date.split('-').reverse().join('/');
        const dateMatch = tx.date.includes(lowerSearch) || formattedDate.includes(lowerSearch);
        if (dateMatch) return true;

        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'compoundInvestment', label: t.compoundInvestment },
          { key: 'others', label: t.others },
        ];

        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && Number((tx as any)[cat.key]) > 0
        );
        if (matchesCategory) return true;

        const totalExpStr = Number(tx.totalExpenses).toFixed(2);
        const dailyCashStr = Number(tx.dailyCash).toFixed(2);
        const totalBalStr = Number(tx.totalBalance).toFixed(2);

        return totalExpStr.includes(lowerSearch) || 
               dailyCashStr.includes(lowerSearch) || 
               totalBalStr.includes(lowerSearch) ||
               tx.totalExpenses.toString().includes(lowerSearch) || 
               tx.dailyCash.toString().includes(lowerSearch) || 
               tx.totalBalance.toString().includes(lowerSearch);
      }
      return true;
    });
  }, [transactions, allTransactions, activeSearch, activeStart, activeEnd, t]);

  const sortedFiltered = useMemo(() => {
    return [...filteredTransactions].sort((a, b) => 
      a.date.localeCompare(b.date) || (a.timestamp || '').localeCompare(b.timestamp || '')
    );
  }, [filteredTransactions]);

  const summary = useMemo(() => {
    if (sortedFiltered.length === 0) return null;

    const totalIncome = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalExpenses = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);

    const firstTx = sortedFiltered[0];
    const startBF = Number(firstTx.broughtForward) || 0;
    const endBalance = startBF + totalIncome - totalExpenses;

    const catKeys = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'compoundInvestment', 'others'];
    const catTotals: Record<string, { actual: number, limit: number }> = {};

    const monthsInView = new Set(sortedFiltered.map(tx => tx.month));
    const isSingleMonth = monthsInView.size === 1;
    const currentMonthLabel = Array.from(monthsInView)[0];
    const activeBudget = isSingleMonth ? budgets.find(b => b.month === currentMonthLabel) : null;

    catKeys.forEach(key => {
      catTotals[key] = {
        actual: sortedFiltered.reduce((sum, tx) => sum + (Number((tx as any)[key]) || 0), 0),
        limit: activeBudget ? (activeBudget.limits as any)[key] : 0
      };
    });

    const budgetAlerts = isSingleMonth ? catKeys.map(key => {
      const { actual: spent, limit } = catTotals[key];
      const isOver = limit > 0 && spent > limit;
      const progress = limit > 0 ? (spent / limit) * 100 : 0;
      return { key, label: (t as any)[key], spent, limit, isOver, progress };
    }).filter(a => a.isOver || (a.limit > 0 && a.progress >= 85)) : [];

    return {
      startBF,
      totalIncome,
      totalExpenses,
      endBalance,
      isSingleMonth,
      currentMonthLabel,
      catTotals,
      budgetAlerts
    };
  }, [sortedFiltered, budgets, t]);

  const exportToExcel = () => {
    if (sortedFiltered.length === 0) return;
    const workbook = XLSX.utils.book_new();

    const formattedData = sortedFiltered.map(tx => ({
      [t.date]: tx.date,
      [t.broughtForward]: Number(tx.broughtForward).toFixed(2),
      [t.dailyCash]: Number(tx.dailyCash).toFixed(2),
      [t.groceries]: Number(tx.groceries).toFixed(2),
      [t.vegetables]: Number(tx.vegetables).toFixed(2),
      [t.fishEgg]: Number(tx.fishEgg).toFixed(2),
      [t.chicken]: Number(tx.chicken).toFixed(2),
      [t.houseRent]: Number(tx.houseRent).toFixed(2),
      [t.electricity]: Number(tx.electricity).toFixed(2),
      [t.water]: Number(tx.water).toFixed(2),
      [t.travel]: Number(tx.travel).toFixed(2),
      [t.compoundInvestment]: Number(tx.compoundInvestment).toFixed(2),
      [t.others]: Number(tx.others).toFixed(2),
      [t.totalExpenses]: Number(tx.totalExpenses).toFixed(2),
      [t.totalBalance]: Number(tx.totalBalance).toFixed(2),
    }));
    const ws = XLSX.utils.json_to_sheet(formattedData);
    XLSX.utils.book_append_sheet(workbook, ws, "Transactions");

    if (summary) {
      const summaryAOA = [
        ["FINANCIAL SUMMARY REPORT"],
        ["Generated Date", new Date().toLocaleString()],
        ["Month / Period", summary.isSingleMonth ? summary.currentMonthLabel : "Filtered Range"],
        [],
        ["SUMMARY METRICS", "AMOUNT"],
        [t.broughtForward, Number(summary.startBF).toFixed(2)],
        [t.totalIncome, Number(summary.totalIncome).toFixed(2)],
        [t.totalExpenses, Number(summary.totalExpenses).toFixed(2)],
        [t.totalBalance, Number(summary.endBalance).toFixed(2)],
        [],
        ["CATEGORY BREAKDOWN", "TOTAL SPENT"],
      ];

      Object.entries(summary.catTotals).forEach(([key, val]: [string, any]) => {
        summaryAOA.push([(t as any)[key], Number(val.actual).toFixed(2)]);
      });

      const wsSummary = XLSX.utils.aoa_to_sheet(summaryAOA);
      XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");
    }

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const clearFilters = () => {
    setStagedSearch(''); setStagedStart(''); setStagedEnd('');
    setActiveSearch(''); setActiveStart(''); setActiveEnd('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleApplyFilters();
  };

  if (isLoading) return <div className="p-12 text-center text-slate-400">Loading records...</div>;

  return (
    <div className="flex flex-col">
      {summary && (
        <div className="p-4 md:p-6 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 transition-colors">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-4 md:mb-6">
            <div className="flex items-center gap-2">
               <PieChart className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
               <h3 className="font-bold text-slate-700 dark:text-slate-300 uppercase text-xs tracking-widest">
                 {summary.isSingleMonth ? `${summary.currentMonthLabel} ${t.summary}` : 'Filtered View Summary'}
               </h3>
            </div>

            {summary.budgetAlerts.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {summary.budgetAlerts.map((alert, idx) => (
                  <div key={idx} className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tight ${alert.isOver ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/30' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/30'}`}>
                    <AlertCircle className="w-3 h-3" />
                    {alert.label}: {alert.isOver ? t.overspent : 'Near Limit'}
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4 mb-4 md:mb-6">
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.broughtForward}</p>
               <p className="text-sm md:text-lg font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(summary.startBF)}</p>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalIncome}</p>
               <div className="flex items-center gap-1 md:gap-2">
                 <TrendingDown className="w-3 md:w-4 h-3 md:h-4 text-emerald-500 rotate-180" />
                 <p className="text-sm md:text-lg font-black text-emerald-600 dark:text-emerald-400">{formatCurrency(summary.totalIncome)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalExpenses}</p>
               <div className="flex items-center gap-1 md:gap-2">
                 <TrendingDown className="w-3 md:w-4 h-3 md:h-4 text-rose-500" />
                 <p className="text-sm md:text-lg font-black text-rose-600 dark:text-rose-400">{formatCurrency(summary.totalExpenses)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-indigo-100 dark:border-indigo-900 shadow-sm bg-indigo-50/20 dark:bg-indigo-900/10">
               <p className="text-[10px] font-black text-indigo-400 uppercase mb-1 tracking-wider">{t.totalBalance}</p>
               <p className="text-sm md:text-lg font-black text-indigo-700 dark:text-indigo-300">{formatCurrency(summary.endBalance)}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-2 md:gap-3">
             {Object.entries(summary.catTotals).map(([key, value]: [string, any]) => (
               <div key={key} className="bg-white/50 dark:bg-slate-900/50 p-2 md:p-3 rounded-lg md:rounded-xl border border-slate-100/50 dark:border-slate-800/50">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">{(t as any)[key]}</p>
                  <div className="flex flex-col">
                    <p className="text-xs md:text-sm font-bold text-slate-700 dark:text-slate-300">{formatCurrency(value.actual)}</p>
                    {value.limit > 0 && (
                      <p className="text-[8px] font-black text-slate-400 dark:text-slate-500 mt-0.5">
                        {t.budget}: {formatCurrency(value.limit)}
                      </p>
                    )}
                  </div>
               </div>
             ))}
          </div>
        </div>
      )}

      <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 space-y-4 no-print transition-colors">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 lg:gap-6">
          <div className="lg:col-span-4 relative group">
            <Search className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${stagedSearch !== activeSearch ? 'text-indigo-500 animate-pulse' : 'text-slate-400'}`} />
            <input 
              type="text" 
              placeholder={t.search} 
              className="w-full pl-11 pr-4 py-2.5 md:py-3 rounded-xl md:rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm" 
              value={stagedSearch} 
              onChange={(e) => setStagedSearch(e.target.value)} 
              onKeyDown={handleKeyDown} 
            />
          </div>
          <div className="lg:col-span-5 flex items-center gap-2">
            <div className={`flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-lg md:rounded-xl px-3 py-2 border transition-colors ${stagedStart !== activeStart ? 'border-indigo-400' : 'border-slate-200 dark:border-slate-700'}`}>
              <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
              <input type="date" className="bg-transparent border-none text-[10px] md:text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedStart} onChange={(e) => setStagedStart(e.target.value)} onKeyDown={handleKeyDown} />
            </div>
            <span className="text-slate-400 font-bold px-1">→</span>
            <div className={`flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-lg md:rounded-xl px-3 py-2 border transition-colors ${stagedEnd !== activeEnd ? 'border-indigo-400' : 'border-slate-200 dark:border-slate-700'}`}>
              <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
              <input type="date" className="bg-transparent border-none text-[10px] md:text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedEnd} onChange={(e) => setStagedEnd(e.target.value)} onKeyDown={handleKeyDown} />
            </div>
          </div>
          <div className="lg:col-span-3 flex items-end gap-2 md:gap-3 h-full">
            <button 
              type="button"
              onClick={(e) => handleApplyFilters(e)} 
              className={`flex-1 flex items-center justify-center gap-2 font-bold text-xs md:text-sm py-2.5 md:py-3 rounded-xl md:rounded-2xl transition-all shadow-lg active:scale-95 ${hasPendingFilters ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}
            >
              <Filter className="w-3.5 md:w-4 h-3.5 md:h-4" />
              {t.applyFilters}
            </button>
            <button type="button" onClick={clearFilters} className="p-2.5 md:p-3 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl md:rounded-2xl transition-all border border-slate-200 dark:border-slate-700">
              <X className="w-4 md:w-5 h-4 md:h-5" />
            </button>
          </div>
        </div>
        <div className="flex flex-wrap items-center justify-between gap-3 pt-2">
          <div className="flex gap-2 md:gap-3">
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold text-[10px] md:text-xs hover:bg-slate-50 dark:hover:bg-slate-700 border border-slate-200 dark:border-slate-700 px-3 md:px-5 py-2 md:py-2.5 rounded-lg md:rounded-xl transition-all"><Printer className="w-3 md:w-3.5 h-3 md:h-3.5" />{t.printReport}</button>
             <button onClick={exportToExcel} className="flex items-center gap-2 bg-emerald-600 text-white font-bold text-[10px] md:text-xs hover:bg-emerald-700 px-3 md:px-5 py-2 md:py-2.5 rounded-lg md:rounded-xl transition-all"><FileSpreadsheet className="w-3 md:w-3.5 h-3 md:h-3.5" />{t.exportExcel}</button>
          </div>
          {hasPendingFilters && <p className="text-[10px] font-bold text-indigo-500 animate-pulse uppercase tracking-tighter">* Changes pending apply</p>}
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left min-w-[1500px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.broughtForward}</th>
              <th className="px-6 py-4">{t.dailyCash}</th>
              <th className="px-4 py-4">{t.groceries}</th>
              <th className="px-4 py-4">{t.vegetables}</th>
              <th className="px-4 py-4">{t.fishEgg}</th>
              <th className="px-4 py-4">{t.chicken}</th>
              <th className="px-4 py-4">{t.houseRent}</th>
              <th className="px-4 py-4">{t.electricity}</th>
              <th className="px-4 py-4">{t.water}</th>
              <th className="px-4 py-4">{t.travel}</th>
              <th className="px-4 py-4">{t.compoundInvestment}</th>
              <th className="px-4 py-4">{t.others}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {sortedFiltered.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-indigo-500 dark:text-indigo-400">{formatCurrency(Number(tx.broughtForward))}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.groceries || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.vegetables || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.fishEgg || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.chicken || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.houseRent || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.electricity || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.water || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.travel || 0))}</td>
                <td className="px-4 py-4 font-bold text-teal-600 dark:text-teal-400">{formatCurrency(Number(tx.compoundInvestment || 0))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{formatCurrency(Number(tx.others || 0))}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button onClick={() => onEdit(tx)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => tx.id && onDelete(tx.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {sortedFiltered.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center gap-4 text-slate-400">
             <Filter className="w-12 h-12 opacity-10" />
             <p className="font-bold italic">{t.noResults}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useMemo } from 'react';
import { Transaction } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell 
} from 'recharts';

interface MonthlyChartsProps {
  t: any;
  transactions: Transaction[];
}

const COLORS = ['#6366f1', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6', '#06b6d4', '#ec4899', '#14b8a6', '#f97316', '#3b82f6'];

const MonthlyCharts: React.FC<MonthlyChartsProps> = ({ t, transactions }) => {
  const isDark = document.documentElement.classList.contains('dark');

  const categoryData = useMemo(() => {
    const data = [
      { name: t.groceries, value: 0 },
      { name: t.vegetables, value: 0 },
      { name: t.fishEgg, value: 0 },
      { name: t.chicken, value: 0 },
      { name: t.houseRent, value: 0 },
      { name: t.electricity, value: 0 },
      { name: t.water, value: 0 },
      { name: t.travel, value: 0 },
      { name: t.compoundInvestment, value: 0 },
      { name: t.others, value: 0 },
    ];

    transactions.forEach(tx => {
      data[0].value += tx.groceries || 0;
      data[1].value += tx.vegetables || 0;
      data[2].value += tx.fishEgg || 0;
      data[3].value += tx.chicken || 0;
      data[4].value += tx.houseRent || 0;
      data[5].value += tx.electricity || 0;
      data[6].value += tx.water || 0;
      data[7].value += tx.travel || 0;
      data[8].value += tx.compoundInvestment || 0;
      data[9].value += tx.others || 0;
    });

    return data.filter(d => d.value > 0);
  }, [transactions, t]);

  if (transactions.length === 0) {
    return (
      <div className="bg-white dark:bg-slate-900 p-12 rounded-3xl border border-slate-100 dark:border-slate-800 text-center transition-colors">
        <p className="text-slate-400 dark:text-slate-600">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
        <h3 className="font-bold text-slate-700 dark:text-slate-300 mb-6">{t.expensesByCategory}</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={categoryData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDark ? "#1e293b" : "#f1f5f9"} />
              <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} stroke={isDark ? "#64748b" : "#94a3b8"} />
              <YAxis fontSize={12} tickLine={false} axisLine={false} stroke={isDark ? "#64748b" : "#94a3b8"} />
              <Tooltip 
                cursor={{fill: isDark ? '#1e293b' : '#f8fafc'}}
                contentStyle={{ 
                  backgroundColor: isDark ? '#0f172a' : '#ffffff', 
                  borderRadius: '12px', 
                  border: isDark ? '1px solid #1e293b' : 'none', 
                  boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                  color: isDark ? '#f1f5f9' : '#1e293b'
                }}
              />
              <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
        <h3 className="font-bold text-slate-700 dark:text-slate-300 mb-6">{t.expenseDistribution}</h3>
        <div className="h-[300px] flex flex-col items-center">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
                stroke={isDark ? "#0f172a" : "#fff"}
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{ 
                  backgroundColor: isDark ? '#0f172a' : '#ffffff', 
                  borderRadius: '12px', 
                  border: isDark ? '1px solid #1e293b' : 'none',
                  color: isDark ? '#f1f5f9' : '#1e293b'
                }}
              />
              <Legend layout="horizontal" align="center" verticalAlign="bottom" />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default MonthlyCharts;

import React, { useState } from 'react';
import { MonthlyBudget } from '../types';

interface BudgetManagerProps {
  t: any;
  month: string;
  initialLimits: MonthlyBudget['limits'];
  onSubmit: (limits: MonthlyBudget['limits']) => void;
}

const BudgetManager: React.FC<BudgetManagerProps> = ({ t, month, initialLimits, onSubmit }) => {
  const [limits, setLimits] = useState(initialLimits);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setLimits(prev => ({
      ...prev,
      [name]: value === '' ? 0 : parseFloat(value)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(limits);
  };

  const fields = [
    { name: 'groceries', label: t.groceries },
    { name: 'vegetables', label: t.vegetables },
    { name: 'fishEgg', label: t.fishEgg },
    { name: 'chicken', label: t.chicken },
    { name: 'houseRent', label: t.houseRent },
    { name: 'electricity', label: t.electricity },
    { name: 'water', label: t.water },
    { name: 'travel', label: t.travel },
    { name: 'compoundInvestment', label: t.compoundInvestment },
    { name: 'others', label: t.others },
  ];

  return (
    <form onSubmit={handleSubmit} className="flex flex-col h-full">
      <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl mb-6 text-center transition-colors">
        <p className="text-[10px] font-black text-indigo-400 dark:text-indigo-500 uppercase tracking-widest mb-1">{t.month}</p>
        <p className="font-bold text-indigo-700 dark:text-indigo-300">{month}</p>
      </div>

      <div className="flex-grow space-y-2 overflow-y-auto pr-1 -mr-1 custom-scrollbar" style={{ maxHeight: 'calc(80vh - 250px)' }}>
        {fields.map(field => (
          <div key={field.name} className="flex items-center justify-between p-3 rounded-2xl bg-slate-50 dark:bg-slate-800/40 border border-slate-100/50 dark:border-slate-700/30 transition-colors">
            <label className="text-xs font-bold text-slate-600 dark:text-slate-400 flex-grow pr-2">
              {field.label}
            </label>
            <div className="relative">
              <input
                type="number"
                name={field.name}
                placeholder="0"
                className="w-24 sm:w-28 px-3 py-2 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-right font-black text-indigo-600 dark:text-indigo-400 text-sm"
                value={(limits as any)[field.name] || ''}
                onChange={handleChange}
              />
            </div>
          </div>
        ))}
      </div>

      <div className="pt-6 mt-auto">
        <button
          type="submit"
          className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-100 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          {t.save}
        </button>
      </div>
    </form>
  );
};

export default BudgetManager;

import React, { useState, useEffect, useMemo } from 'react';
import { Bill, Transaction } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X, TrendingUp, ReceiptText, CheckCircle2, Search, Filter, ArrowUpDown, AlertCircle } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  transactions: Transaction[];
  onRefresh?: () => void;
}

const CATEGORY_COLORS: Record<string, { dot: string; bg: string; text: string }> = {
  groceries: { dot: 'bg-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-900/20', text: 'text-indigo-600 dark:text-indigo-400' },
  vegetables: { dot: 'bg-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/20', text: 'text-emerald-600 dark:text-emerald-400' },
  fishEgg: { dot: 'bg-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-600 dark:text-blue-400' },
  chicken: { dot: 'bg-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/20', text: 'text-orange-600 dark:text-orange-400' },
  houseRent: { dot: 'bg-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/20', text: 'text-rose-600 dark:text-rose-400' },
  electricity: { dot: 'bg-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-900/20', text: 'text-yellow-600 dark:text-yellow-400' },
  water: { dot: 'bg-cyan-500', bg: 'bg-cyan-50 dark:bg-cyan-900/20', text: 'text-cyan-600 dark:text-cyan-400' },
  travel: { dot: 'bg-purple-500', bg: 'bg-purple-50 dark:bg-purple-900/20', text: 'text-purple-600 dark:text-purple-400' },
  compoundInvestment: { dot: 'bg-teal-500', bg: 'bg-teal-50 dark:bg-teal-900/20', text: 'text-teal-600 dark:text-teal-400' },
  others: { dot: 'bg-slate-500', bg: 'bg-slate-50 dark:bg-slate-800/50', text: 'text-slate-600 dark:text-slate-400' },
};

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, transactions, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: new Date().getDate(), category: 'others' });
  const [isNameManuallyEdited, setIsNameManuallyEdited] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);

  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('all');
  const [sortBy, setSortBy] = useState<'day' | 'name' | 'amount'>('day');

  useEffect(() => {
    storageService.fetchBills().then(setBills).catch(e => console.error("Bills fetch error", e));
  }, []);

  const currentMonthLabel = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const filteredBills = useMemo(() => {
    return bills
      .filter(bill => {
        const name = bill.name || "";
        const matchesSearch = name.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = categoryFilter === 'all' || bill.category === categoryFilter;
        return matchesSearch && matchesCategory;
      })
      .sort((a, b) => {
        if (sortBy === 'day') return (a.dueDay || 0) - (b.dueDay || 0);
        if (sortBy === 'amount') return (b.amount || 0) - (a.amount || 0);
        return (a.name || "").localeCompare(b.name || "");
      });
  }, [bills, searchTerm, categoryFilter, sortBy]);

  const handleCategoryChange = (category: string) => {
    const updates: Partial<Bill> = { category };
    if (!isNameManuallyEdited || !newBill.name) {
      updates.name = t[category as keyof typeof t] || category;
    }
    setNewBill(prev => ({ ...prev, ...updates }));
  };

  const handleSave = async () => {
    setValidationError(null);
    if (!newBill.name?.trim()) {
      setValidationError("Bill name is required");
      return;
    }
    if (newBill.amount === undefined || newBill.amount === null || Number(newBill.amount) <= 0) {
      setValidationError("Please enter a valid amount greater than 0");
      return;
    }
    if (newBill.dueDay === undefined || newBill.dueDay === null || Number(newBill.dueDay) < 1 || Number(newBill.dueDay) > 31) {
      setValidationError("Please enter a valid due day between 1 and 31");
      return;
    }

    try {
      const bill: Bill = {
        id: crypto.randomUUID(),
        name: newBill.name.trim(),
        amount: Number(newBill.amount),
        dueDay: Number(newBill.dueDay),
        category: newBill.category || 'others'
      };

      const success = await storageService.saveBill(bill);
      if (success) {
        setBills(prev => [...prev, bill]);
        setShowAdd(false);
        resetForm();
        if (onRefresh) onRefresh();
      } else {
        throw new Error("Storage failure");
      }
    } catch (e) {
      setValidationError("An error occurred while saving. Please try again.");
    }
  };

  const resetForm = () => {
    setNewBill({ dueDay: new Date().getDate(), category: 'others' });
    setIsNameManuallyEdited(false);
    setValidationError(null);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      try {
        const success = await storageService.deleteBill(id);
        if (success) {
          setBills(prev => prev.filter(b => b.id !== id));
          if (onRefresh) onRefresh();
        }
      } catch (e) {
        alert("Delete failed.");
      }
    }
  };

  const handlePayBill = async (bill: Bill) => {
    try {
      const updatedBill: Bill = { ...bill, lastPaidMonth: currentMonthLabel };
      const success = await storageService.saveBill(updatedBill);
      if (success) {
        setBills(prev => prev.map(b => b.id === bill.id ? updatedBill : b));
        if (onRefresh) onRefresh();
      }
    } catch (e) {
      alert("Payment recording failed.");
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row gap-4 no-print">
        <div className="relative flex-grow">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" placeholder={t.search} 
            className="w-full pl-11 pr-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm"
            value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2">
          <select 
            className="px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 font-bold text-xs outline-none"
            value={categoryFilter} onChange={e => setCategoryFilter(e.target.value)}
          >
            <option value="all">All Categories</option>
            {Object.keys(CATEGORY_COLORS).map(cat => (
              <option key={cat} value={cat}>{t[cat as keyof typeof t] || cat}</option>
            ))}
          </select>
          <select 
            className="px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 font-bold text-xs outline-none"
            value={sortBy} onChange={e => setSortBy(e.target.value as any)}
          >
            <option value="day">Day</option>
            <option value="name">Name</option>
            <option value="amount">Amount</option>
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredBills.map(bill => {
          const isPaidThisMonth = bill.lastPaidMonth === currentMonthLabel;
          const style = CATEGORY_COLORS[bill.category] || CATEGORY_COLORS.others;
          return (
            <div 
              key={bill.id} 
              className={`bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-all duration-300 ${isPaidThisMonth ? 'opacity-60 grayscale-[0.4]' : ''}`}
            >
              <div className={`absolute top-0 left-0 w-1.5 h-full transition-all ${isPaidThisMonth ? 'bg-emerald-500' : style.dot}`} />
              <div className="flex justify-between items-start mb-4 pl-2">
                <div>
                  <h3 className={`font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight ${isPaidThisMonth ? 'line-through' : ''}`}>
                    {bill.name}
                  </h3>
                  <p className={`text-[10px] font-black uppercase tracking-widest ${style.text}`}>
                    {t[bill.category as keyof typeof t] || bill.category}
                  </p>
                </div>
                <button 
                  onClick={() => handleDelete(bill.id)}
                  className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>

              <div className="flex items-center gap-6 pl-2 mb-6">
                <div className="flex flex-col">
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Due Day</span>
                  <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                    <Calendar className="w-4 h-4" />
                    <span>{bill.dueDay}</span>
                  </div>
                </div>
                <div className="flex flex-col">
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                  <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-slate-800 dark:text-slate-100'}`}>
                    <span>{formatCurrency(bill.amount)}</span>
                  </div>
                </div>
              </div>

              <div className="pl-2">
                {isPaidThisMonth ? (
                  <div className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400 font-black text-xs uppercase tracking-widest bg-emerald-50 dark:bg-emerald-950/30 py-2 px-4 rounded-xl">
                    <CheckCircle2 className="w-4 h-4" /> {t.paid}
                  </div>
                ) : (
                  <button 
                    onClick={() => handlePayBill(bill)}
                    className={`w-full flex items-center justify-center gap-2 text-white font-bold text-xs uppercase tracking-widest py-3 rounded-xl transition-all shadow-md active:scale-95 ${style.dot} hover:brightness-[1.1]`}
                  >
                    <CheckCircle2 className="w-4 h-4" /> {t.payBill}
                  </button>
                )}
              </div>
            </div>
          );
        })}
        {filteredBills.length === 0 && !isLoading && (
          <div className="col-span-full p-20 text-center flex flex-col items-center gap-4 text-slate-400">
             <ReceiptText className="w-12 h-12 opacity-10" />
             <p className="font-bold italic">No bills found</p>
          </div>
        )}
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl dark:shadow-none overflow-hidden animate-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.addBill}</h3>
              <button onClick={() => { setShowAdd(false); resetForm(); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 space-y-4 overflow-y-auto">
              {validationError && (
