                  value={newBill.category || 'others'} onChange={e => handleCategoryChange(e.target.value)}
                >
                  {Object.keys(CATEGORY_COLORS).map(cat => <option key={cat} value={cat}>{t[cat as keyof typeof t] || cat}</option>)}
                </select>
