  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [toast, setToast] = useState<ToastState | null>(null);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>(() => {
    const saved = localStorage.getItem('currency_settings');
    return saved ? JSON.parse(saved) : { symbol: 'Rs', position: 'before' };
  });

  const t = translations[lang];

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  useEffect(() => {
    localStorage.setItem('lang', lang);
  }, [lang]);

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setToast({ message, type });
  };

  const handleLogout = () => {
    if (window.confirm(t.logout + "?")) {
      localStorage.removeItem('finance_user');
      setUser(null);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    try {
      const dummyUser = { name: email.split('@')[0], email };
      localStorage.setItem('finance_user', JSON.stringify(dummyUser));
      setUser(dummyUser);
      showToast(t.welcomeBack, 'success');
    } catch (err) {
      showToast(t.authError, 'error');
    }
  };

  const handleRegister = async (name: string, email: string, pass: string) => {
    try {
      const dummyUser = { name, email };
      localStorage.setItem('finance_user', JSON.stringify(dummyUser));
      setUser(dummyUser);
      showToast(t.settingsSaved, 'success');
    } catch (err) {
      showToast(t.authError, 'error');
    }
  };

  const formatCurrency = useCallback((amount: number) => {
    const formattedAmount = amount.toLocaleString(undefined, { 
      minimumFractionDigits: 2, 
      maximumFractionDigits: 2 
    });
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  const recalculateChain = useCallback((txs: Transaction[]) => {
    if (txs.length === 0) return [];

    const sorted = [...txs].sort((a, b) => {
      const dateDiff = a.date.localeCompare(b.date);
      if (dateDiff !== 0) return dateDiff;
      return (a.timestamp || '').localeCompare(b.timestamp || '');
    });

    const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'compoundInvestment', 'others'];

    let runningBalance = 0;
    return sorted.map((tx, index) => {
      const bf = index === 0 ? Number(tx.broughtForward || 0) : runningBalance;
      const income = Number(tx.dailyCash || 0);
      const expense = categories.reduce((sum, cat) => sum + (Number((tx as any)[cat]) || 0), 0);
      const totalBalance = bf + income - expense;

      runningBalance = totalBalance;

      return {
        ...tx,
        broughtForward: bf,
        totalExpenses: expense,
        totalBalance: totalBalance
      };
    });
  }, []);

  const getStartingBalance = useCallback((targetDate: string) => {
    if (!transactions || transactions.length === 0) return 0;

    const sorted = [...transactions].sort((a, b) => {
      const dateDiff = a.date.localeCompare(b.date);
      if (dateDiff !== 0) return dateDiff;
      return (a.timestamp || '').localeCompare(b.timestamp || '');
    });

    const sameDayEntry = sorted.find(tx => tx.date === targetDate);
    if (sameDayEntry) return Number(sameDayEntry.broughtForward || 0);

    const lastValidEntry = [...sorted].reverse().find(tx => tx.date < targetDate);

    if (lastValidEntry) return Number(lastValidEntry.totalBalance || 0);
    return 0;
  }, [transactions]);

  const generateNotifications = useCallback(async (txs: Transaction[]) => {
    try {
      const budgets = await storageService.fetchBudgets();
      const bills = await storageService.fetchBills();
      const now = new Date();
      const currentMonthLabel = now.toLocaleString('en-US', { month: 'long', year: 'numeric' });
      const currentMonthTxs = txs.filter(tx => tx.month === currentMonthLabel);
      const budget = budgets.find(b => b.month === currentMonthLabel);
      const newNotifications: Notification[] = [];

      if (budget) {
        const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'compoundInvestment', 'others'];
        categories.forEach(cat => {
          const limit = (budget.limits as any)[cat];
          const spent = currentMonthTxs.reduce((sum, tx) => sum + (Number((tx as any)[cat]) || 0), 0);
          if (limit > 0 && spent / limit >= 0.85) {
            newNotifications.push({
              id: `budget-${cat}-${currentMonthLabel}`,
              type: 'budget',
              title: t.lowBudgetAlert,
              message: t.lowBudgetMsg.replace('{percent}', Math.round((spent/limit)*100).toString()).replace('{category}', (t as any)[cat]),
              timestamp: now.toISOString(),
              read: false,
              priority: spent >= limit ? 'high' : 'medium'
            });
          }
        });
      }

      bills.forEach(bill => {
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        let dueDate = new Date(now.getFullYear(), now.getMonth(), bill.dueDay);
        if (dueDate < today) dueDate = new Date(now.getFullYear(), now.getMonth() + 1, bill.dueDay);
        const diffTime = dueDate.getTime() - today.getTime();
        const daysLeft = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        if (daysLeft >= 0 && daysLeft <= 7) {
          newNotifications.push({
            id: `bill-${bill.id}-${dueDate.toISOString().split('T')[0]}`,
            type: 'bill',
            title: bill.name,
            message: daysLeft === 0 ? t.dueToday : t.billDueIn.replace('{days}', daysLeft.toString()),
            timestamp: now.toISOString(),
            read: false,
            priority: daysLeft === 0 ? 'high' : (daysLeft <= 3 ? 'medium' : 'low')
          });
        }
      });

      setNotifications(prev => {
        const existingIds = new Set(prev.map(n => n.id));
        const added = newNotifications.filter(n => !existingIds.has(n.id));
        return [...added, ...prev].slice(0, 30);
      });
    } catch (e) {
      console.error("Notification sync failed", e);
    }
  }, [t]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      const rebalanced = recalculateChain(data);
      setTransactions(rebalanced);
      await generateNotifications(rebalanced);
    } catch (err) {
      showToast("Data loading error. Local storage might be full.", 'error');
    } finally {
      setIsLoading(false);
    }
  }, [generateNotifications, recalculateChain]);

  const onAddTransaction = useCallback(async (data: Transaction) => {
    setIsSyncing(true);
    try {
      const freshTransactions = await storageService.fetchTransactions();
      const existingIndex = freshTransactions.findIndex(tx => tx.date === data.date);

      let newList;
      if (existingIndex !== -1) {
        const existing = freshTransactions[existingIndex];
        const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'compoundInvestment', 'others'];
        const merged: Transaction = {
          ...existing,
          dailyCash: Number(existing.dailyCash || 0) + Number(data.dailyCash || 0),
          timestamp: new Date().toISOString()
        };
        categories.forEach(cat => {
          (merged as any)[cat] = Number((existing as any)[cat] || 0) + Number((data as any)[cat] || 0);
        });
        newList = [...freshTransactions];
        newList[existingIndex] = merged;
      } else {
        newList = [...freshTransactions, { ...data, id: crypto.randomUUID(), timestamp: new Date().toISOString() }];
      }

      const rebalanced = recalculateChain(newList);
      await storageService.saveAllTransactions(rebalanced);
      await loadData();
      showToast(t.saveSettings, 'success');
    } catch (err) {
      showToast("Could not save transaction.", 'error');
    } finally {
      setIsSyncing(false);
    }
  }, [loadData, recalculateChain, t.saveSettings]);

  const onUpdateTransaction = useCallback(async (id: string, data: Transaction) => {
    setIsSyncing(true);
    try {
      const freshTransactions = await storageService.fetchTransactions();
      const updatedList = freshTransactions.map(tx => tx.id === id ? { ...data, id } : tx);
      const rebalanced = recalculateChain(updatedList);
      await storageService.saveAllTransactions(rebalanced);
      await loadData();
      showToast("Updated successfully", 'success');
    } catch (err) {
      showToast("Update failed", 'error');
    } finally {
      setIsSyncing(false);
    }
  }, [loadData, recalculateChain]);

  const onDeleteTransaction = useCallback(async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      setIsSyncing(true);
      try {
        const freshTransactions = await storageService.fetchTransactions();
        const updatedList = freshTransactions.filter(tx => tx.id !== id);
        const rebalanced = recalculateChain(updatedList);
        await storageService.saveAllTransactions(rebalanced);
        await loadData();
        showToast("Deleted successfully", 'success');
      } catch (err) {
        showToast("Delete failed", 'error');
      } finally {
        setIsSyncing(false);
      }
    }
  }, [loadData, t.confirmDelete, recalculateChain]);

  useEffect(() => {
    if (user) loadData();
  }, [user, loadData]);

  if (!user) {
    return <AuthForm t={t} onLogin={handleLogin} onRegister={handleRegister} />;
  }

  const navItems = [
    { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
    { id: 'analytics', label: t.charts, icon: BarChart3 },
    { id: 'investments', label: t.investments, icon: TrendingUp },
    { id: 'budget', label: t.budget, icon: Target },
    { id: 'bills', label: t.bills, icon: CreditCard },
    { id: 'history', label: t.history, icon: History },
    { id: 'settings', label: t.settings, icon: Settings },
  ];

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-24 md:pb-0 font-sans transition-colors duration-300">
      {toast && (
        <div className="fixed bottom-24 md:bottom-8 right-4 md:right-8 z-[100] animate-in slide-in-from-right-8 duration-300">
          <div className={`px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 border ${
            toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 
            toast.type === 'error' ? 'bg-rose-600 border-rose-500 text-white' : 
            'bg-indigo-600 border-indigo-500 text-white'
          }`}>
            {toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
            <span className="font-black text-sm uppercase tracking-tight">{toast.message}</span>
          </div>
        </div>
      )}

      {isSyncing && (
        <div className="fixed top-4 right-4 z-[90] bg-white/90 dark:bg-slate-900/90 backdrop-blur-md px-4 py-2 rounded-2xl border border-indigo-100 dark:border-indigo-900 shadow-xl flex items-center gap-3">
          <RefreshCw className="w-4 h-4 text-indigo-500 animate-spin" />
          <span className="text-[10px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">{t.calculating}</span>
        </div>
      )}

      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 z-20 no-print transition-colors">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-200 dark:shadow-none">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 dark:text-slate-100 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          {navItems.map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === tab.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              <tab.icon className="w-5 h-5" />
              {tab.label}
            </button>
          ))}
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 dark:border-slate-800 pt-6">
          <button onClick={() => setIsDark(!isDark)} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            {isDark ? t.lightMode : t.darkMode}
          </button>
          <button onClick={() => setLang(lang === 'en' ? 'si' : 'en')} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 font-medium transition-colors">
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
          <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 font-bold rounded-xl transition-all mt-4">
            <LogOut className="w-5 h-5" />
            {t.logout}
          </button>
        </div>
      </nav>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/80 dark:bg-slate-900/80 backdrop-blur-lg border-t border-slate-200 dark:border-slate-800 px-2 py-3 z-50 no-print flex justify-around items-center transition-colors">
        {navItems.map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex flex-col items-center gap-1 transition-all flex-1 min-w-0 ${activeTab === tab.id ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-400 dark:text-slate-500'}`}
          >
            <tab.icon className={`w-5 h-5 ${activeTab === tab.id ? 'scale-110' : 'scale-100'}`} />
            <span className="text-[9px] font-bold uppercase tracking-tight truncate w-full text-center">{tab.label}</span>
          </button>
        ))}
      </nav>

      <header className="md:hidden bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-2 flex items-center justify-between sticky top-0 z-30 no-print transition-colors shadow-sm">
        <div className="flex items-center gap-2">
          <Wallet className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          <h1 className="font-bold text-xs text-slate-800 dark:text-slate-100 truncate max-w-[150px]">{t.title}</h1>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <Bell className="w-4 h-4" />
            {notifications.filter(n => !n.read).length > 0 && <span className="absolute top-1.5 right-1.5 w-1.5 h-1.5 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setIsDark(!isDark)} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            {isDark ? <Sun className="w-4 h-4" /> : <Moon className="w-4 h-4" />}
          </button>
        </div>
      </header>

      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-3 md:p-8">
          {activeTab === 'settings' && (
            <SettingsPage 
              t={t} 
              lang={lang}
              onLanguageChange={setLang}
              settings={currencySettings} 
              isDark={isDark}
              onToggleDark={() => setIsDark(!isDark)}
              onSave={(s) => { setCurrencySettings(s); localStorage.setItem('currency_settings', JSON.stringify(s)); showToast(t.settingsSaved, 'success'); }} 
            />
          )}
          {activeTab === 'bills' && <BillManager t={t} formatCurrency={formatCurrency} transactions={transactions} onRefresh={loadData} />}
          {activeTab === 'investments' && <InvestmentTracker t={t} formatCurrency={formatCurrency} transactions={transactions} />}
          {activeTab !== 'settings' && activeTab !== 'bills' && activeTab !== 'investments' && (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
              isLoading={isLoading}
              formatCurrency={formatCurrency}
              notifications={notifications}
              getStartingBalance={getStartingBalance}
            />
          )}
        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget, Notification } from '../types.ts';
import TransactionForm from './TransactionForm.tsx';
import StatsOverview from './StatsOverview.tsx';
import MonthlyCharts from './MonthlyCharts.tsx';
import HistoryTable from './HistoryTable.tsx';
import BudgetManager from './BudgetManager.tsx';
import BudgetPerformance from './BudgetPerformance.tsx';
import { 
  Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, 
  AlertCircle, Clock, History, BellRing, TriangleAlert, Zap, 
  CheckCircle2, ArrowRightCircle, ShoppingBag, Leaf, Fish, 
  Drumstick, Home, Droplets, Car, PlusCircle, LayoutGrid, CalendarDays,
  ChevronDown, TrendingUp
} from 'lucide-react';
import { storageService } from '../services/googleSheets.ts';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings' | 'investments';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings' | 'investments') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  notifications?: Notification[];
  getStartingBalance: (date: string) => number;
}

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency,
  notifications = [],
  getStartingBalance
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  const now = new Date();
  const [selectedYear, setSelectedYear] = useState<number>(now.getFullYear());
  const [selectedMonthName, setSelectedMonthName] = useState<string>(now.toLocaleString('en-US', { month: 'long' }));

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const availableYears = useMemo(() => {
    const years = new Set<number>();
    const currentYear = new Date().getFullYear();

    for (let i = currentYear - 5; i <= currentYear + 2; i++) {
      years.add(i);
    }

    transactions.forEach(tx => {
      const d = new Date(tx.date);
      if (!isNaN(d.getTime())) {
        years.add(d.getFullYear());
      }
    });

    return Array.from(years).sort((a, b) => b - a);
  }, [transactions]);

  const selectedMonthKey = `${selectedMonthName} ${selectedYear}`;

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonthKey) || {
      month: selectedMonthKey,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, compoundInvestment: 0, others: 0 }
    };
  }, [budgets, selectedMonthKey]);

  const currentMonthTransactions = useMemo(() => {
    return transactions
      .filter(tx => tx.month?.trim() === selectedMonthKey)
      .sort((a, b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));
  }, [transactions, selectedMonthKey]);

  const categorySummary = useMemo(() => {
    const categories = [
      { key: 'groceries', label: t.groceries, icon: ShoppingBag, color: 'text-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-900/20' },
      { key: 'vegetables', label: t.vegetables, icon: Leaf, color: 'text-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/20' },
      { key: 'fishEgg', label: t.fishEgg, icon: Fish, color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/20' },
      { key: 'chicken', label: t.chicken, icon: Drumstick, color: 'text-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/20' },
      { key: 'houseRent', label: t.houseRent, icon: Home, color: 'text-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/20' },
      { key: 'electricity', label: t.electricity, icon: Zap, color: 'text-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-900/20' },
      { key: 'water', label: t.water, icon: Droplets, color: 'text-cyan-500', bg: 'bg-cyan-50 dark:bg-cyan-900/20' },
      { key: 'travel', label: t.travel, icon: Car, color: 'text-purple-500', bg: 'bg-purple-50 dark:bg-purple-900/20' },
      { key: 'compoundInvestment', label: t.compoundInvestment, icon: TrendingUp, color: 'text-teal-500', bg: 'bg-teal-50 dark:bg-teal-900/20' },
      { key: 'others', label: t.others, icon: PlusCircle, color: 'text-slate-500', bg: 'bg-slate-50 dark:bg-slate-800/50' },
    ];

    return categories.map(cat => {
      const total = currentMonthTransactions.reduce((sum, tx) => sum + (Number((tx as any)[cat.key]) || 0), 0);
      const limit = (activeBudget.limits as any)[cat.key] || 0;
      return { ...cat, total, limit };
    });
  }, [currentMonthTransactions, activeBudget, t]);

  const budgetHealth = useMemo(() => {
    const issues = categorySummary
      .filter(cat => cat.limit > 0 && (cat.total / cat.limit) * 100 >= 80)
      .map(cat => ({
        category: cat.key,
        label: cat.label,
        spent: cat.total,
        limit: cat.limit,
        percentage: (cat.total / cat.limit) * 100,
        status: (cat.total / cat.limit) * 100 >= 100 ? 'over' : 'warning'
      }));

    return issues.sort((a, b) => b.percentage - a.percentage);
  }, [categorySummary]);

  const filteredStats = useMemo(() => {
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const sorted = [...currentMonthTransactions].sort((a, b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));
    const firstTx = sorted[0];
    const initialBF = firstTx ? (Number(firstTx.broughtForward) || 0) : 0;
    const totalDailyCash = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalAvailableFunds = initialBF + totalDailyCash;
    const currentNetBalance = totalAvailableFunds - totalSpent;
    return { totalSpent, totalReceived: totalAvailableFunds, lastBalance: currentNetBalance };
  }, [currentMonthTransactions]);

  const recentTransactions = useMemo(() => {
