        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Wallet, Mail, Lock, User, ArrowRight, Loader2, AlertCircle, Eye, EyeOff } from 'lucide-react';

interface AuthFormProps {
  t: any;
  onLogin: (email: string, pass: string) => Promise<void>;
  onRegister: (name: string, email: string, pass: string) => Promise<void>;
}

const AuthForm: React.FC<AuthFormProps> = ({ t, onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [rememberMe, setRememberMe] = useState(true);
  const [error, setError] = useState('');

  const validateEmail = (email: string) => {
    return String(email)
      .toLowerCase()
      .match(
        /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
      );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!validateEmail(formData.email)) {
      setError("Please enter a valid email address");
      return;
    }

    if (formData.password.length < 4) {
      setError("Password must be at least 4 characters");
      return;
    }

    if (!isLogin && !formData.name.trim()) {
      setError("Full name is required");
      return;
    }

    setLoading(true);
    try {
      if (isLogin) {
        await onLogin(formData.email, formData.password);
      } else {
        await onRegister(formData.name, formData.email, formData.password);
      }
    } catch (err) {
      setError(t.authError || "Authentication failed. Try again.");
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-50 dark:bg-slate-950 font-sans transition-colors duration-300">
      <div className="w-full max-w-md">
        <div className="text-center mb-10 animate-in fade-in slide-in-from-top-6 duration-700">
          <div className="inline-flex p-4 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-200 dark:shadow-none mb-6">
            <Wallet className="w-10 h-10 text-white" />
          </div>
          <h1 className="text-3xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{t.title}</h1>
          <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium">{isLogin ? t.welcomeBack : t.createAccount}</p>
        </div>

        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-xl shadow-slate-200/50 dark:shadow-none animate-in zoom-in-95 duration-500">
          {error && (
            <div className="mb-6 p-4 bg-rose-50 dark:bg-rose-900/20 border border-rose-100 dark:border-rose-900/50 rounded-2xl flex items-center gap-3 text-rose-600 dark:text-rose-400 text-xs font-black uppercase tracking-tight animate-in fade-in slide-in-from-top-2">
              <AlertCircle className="w-4 h-4 shrink-0" /> {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            {!isLogin && (
              <div className="space-y-1">
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1">{t.fullName}</label>
                <div className="relative group">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                  <input
                    required type="text"
                    name="name"
                    autoComplete="name"
                    className="w-full pl-12 pr-4 py-3.5 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-semibold"
                    placeholder="John Doe" value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1">{t.email}</label>
              <div className="relative group">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input
                  required type="email"
                  name="email"
                  autoComplete="email"
                  className="w-full pl-12 pr-4 py-3.5 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-semibold"
                  placeholder="name@example.com" value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1">{t.password}</label>
              <div className="relative group">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input
                  required type={showPassword ? 'text' : 'password'}
                  name="password"
                  autoComplete={isLogin ? "current-password" : "new-password"}
                  className="w-full pl-12 pr-12 py-3.5 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-semibold"
                  placeholder="••••••••" value={formData.password}
                  onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                />
                <button 
                  type="button"
                  onClick={togglePasswordVisibility}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-500 transition-colors focus:outline-none"
                >
                  {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                </button>
              </div>
            </div>

            <div className="flex items-center justify-between px-1">
              <label className="flex items-center gap-2 cursor-pointer group">
                <input 
                  type="checkbox" 
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                  className="w-4 h-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                />
                <span className="text-xs font-bold text-slate-500 dark:text-slate-400 group-hover:text-indigo-600 transition-colors">{t.rememberMe}</span>
              </label>
            </div>

            <button
              disabled={loading} type="submit"
              className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none transition-all active:scale-[0.98] disabled:opacity-70"
            >
              {loading ? (
                <Loader2 className="w-5 h-5 animate-spin" />
              ) : (
                <>
                  {isLogin ? t.login : t.register}
                  <ArrowRight className="w-5 h-5" />
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-100 dark:border-slate-800 text-center">
            <button
              onClick={() => { setIsLogin(!isLogin); setError(''); }}
              className="text-sm font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 transition-colors"
            >
              {isLogin ? t.noAccount : t.hasAccount}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthForm;

import React, { useMemo } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  Cell, AreaChart, Area
} from 'recharts';
import { Target, TrendingUp, TrendingDown, AlertCircle, CheckCircle2, ArrowRightCircle, MoveUpRight, MoveDownRight, Activity } from 'lucide-react';

interface BudgetPerformanceProps {
  t: any;
  transactions: Transaction[];
  budgets: MonthlyBudget[];
  formatCurrency: (amount: number) => string;
}

const CATEGORIES = [
  'groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 
  'electricity', 'water', 'travel', 'compoundInvestment', 'others'
];

const BudgetPerformance: React.FC<BudgetPerformanceProps> = ({ t, transactions, budgets, formatCurrency }) => {
  const isDark = document.documentElement.classList.contains('dark');

  const performanceData = useMemo(() => {
    const months = Array.from(new Set([
      ...transactions.map(tx => tx.month.trim()),
      ...budgets.map(b => b.month.trim())
    ])).sort((a, b) => new Date(a).getTime() - new Date(b).getTime());

    return months.map(month => {
      const monthTxs = transactions.filter(tx => tx.month.trim() === month);
      const monthBudget = budgets.find(b => b.month.trim() === month);

      const actual = monthTxs.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
      const budget = monthBudget ? (Object.values(monthBudget.limits) as number[]).reduce((sum, limit) => sum + (Number(limit) || 0), 0) : 0;

      const categorySpend = CATEGORIES.reduce((acc, cat) => {
        acc[cat] = monthTxs.reduce((sum, tx) => sum + (Number((tx as any)[cat]) || 0), 0);
        return acc;
      }, {} as Record<string, number>);

      return {
        month,
        actual,
        budget,
        difference: budget - actual,
        status: (budget > 0) ? (actual <= budget ? 'under' : 'over') : 'no-budget',
        categorySpend
      };
    }).filter(d => d.budget > 0 || d.actual > 0);
  }, [transactions, budgets]);

  const comparison = useMemo(() => {
    if (performanceData.length < 2) return null;

    const current = performanceData[performanceData.length - 1];
    const previous = performanceData[performanceData.length - 2];

    const totalChange = current.actual - previous.actual;
    const percentChange = previous.actual > 0 ? (totalChange / previous.actual) * 100 : 0;

    const categoryTrends = CATEGORIES.map(cat => {
      const curr = current.categorySpend[cat] || 0;
      const prev = previous.categorySpend[cat] || 0;
      const diff = curr - prev;
      const pct = prev > 0 ? (diff / prev) * 100 : (curr > 0 ? 100 : 0);
      return { 
        key: cat, 
        label: t[cat], 
        curr, 
        prev, 
        diff, 
        pct,
        status: diff <= 0 ? 'improved' : 'declined' 
      };
    }).filter(t => t.curr > 0 || t.prev > 0);

    return { current, previous, totalChange, percentChange, categoryTrends };
  }, [performanceData, t]);

  if (performanceData.length === 0) {
    return (
      <div className="bg-white dark:bg-slate-900 p-12 rounded-3xl border border-slate-100 dark:border-slate-800 text-center transition-colors">
        <p className="text-slate-400 dark:text-slate-600">{t.noData}</p>
      </div>
    );
  }

  const latestPerformance = performanceData[performanceData.length - 1];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <Target className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.budgetPerformance}</h2>
        </div>

        {comparison && (
          <div className={`px-4 py-2 rounded-2xl flex items-center gap-3 border ${comparison.totalChange <= 0 ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100 dark:border-emerald-900/50' : 'bg-rose-50 dark:bg-rose-900/20 border-rose-100 dark:border-rose-900/50'}`}>
            <div className={`p-1.5 rounded-lg ${comparison.totalChange <= 0 ? 'bg-emerald-500' : 'bg-rose-500'}`}>
               {comparison.totalChange <= 0 ? <MoveDownRight className="w-4 h-4 text-white" /> : <MoveUpRight className="w-4 h-4 text-white" />}
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">{t.vsLastMonth}</p>
              <p className={`text-sm font-black ${comparison.totalChange <= 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-rose-600 dark:text-rose-400'}`}>
                {comparison.percentChange > 0 ? '+' : ''}{comparison.percentChange.toFixed(1)}%
              </p>
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Main Performance Bar Chart */}
        <div className="lg:col-span-8 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
          <div className="flex items-center justify-between mb-8">
            <h3 className="font-bold text-slate-700 dark:text-slate-300">{t.budgetVsActual}</h3>
            <div className="flex gap-4">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-indigo-500 rounded-full" />
                <span className="text-[10px] font-bold text-slate-400 uppercase">{t.budgetLimit}</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-emerald-500 rounded-full" />
                <span className="text-[10px] font-bold text-slate-400 uppercase">{t.actualSpending}</span>
              </div>
            </div>
          </div>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={performanceData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDark ? "#1e293b" : "#f1f5f9"} />
