import React, { useState, useMemo, useEffect } from 'react';
import { Transaction } from '../types';
import { TrendingUp, Target, Calculator, Info, Calendar, ChevronDown, ArrowUpRight, BarChart4, Wallet, Save, RotateCcw, RefreshCw, Sparkles, CheckCircle2 } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface InvestmentTrackerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  transactions: Transaction[];
}

const STORAGE_KEY = 'finance_tracker_v3_investment_plan';

const InvestmentTracker: React.FC<InvestmentTrackerProps> = ({ t, formatCurrency, transactions }) => {
  const isDark = document.documentElement.classList.contains('dark');

  // 1. Calculate actual stats from dashboard transactions
  const totalActualInvested = useMemo(() => {
    return transactions.reduce((sum, tx) => sum + (Number(tx.compoundInvestment) || 0), 0);
  }, [transactions]);

  const suggestedMonthlyContribution = useMemo(() => {
    if (transactions.length === 0) return 1000;
    // Look at last 60 days
    const sixtyDaysAgo = new Date();
    sixtyDaysAgo.setDate(sixtyDaysAgo.getDate() - 60);

    const recentInvestments = transactions.filter(tx => new Date(tx.date) >= sixtyDaysAgo);
    const totalRecent = recentInvestments.reduce((sum, tx) => sum + (Number(tx.compoundInvestment) || 0), 0);

    // Average monthly based on the 2 month window
    return Math.max(Math.round(totalRecent / 2), 0) || 1000;
  }, [transactions]);

  // Load saved settings from localStorage
  const savedSettings = useMemo(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : null;
  }, []);

  const [principal, setPrincipal] = useState<number>(savedSettings?.principal ?? totalActualInvested ?? 10000);
  const [contributionAmount, setContributionAmount] = useState<number>(savedSettings?.contributionAmount ?? suggestedMonthlyContribution);
  const [contributionFrequency, setContributionFrequency] = useState<'daily' | 'monthly'>(savedSettings?.contributionFrequency ?? 'monthly');
  const [annualRate, setAnnualRate] = useState<number>(savedSettings?.annualRate ?? 8);
  const [years, setYears] = useState<number>(savedSettings?.years ?? 10);
  const [compoundingFreq, setCompoundingFreq] = useState<number>(savedSettings?.compoundingFreq ?? 12);
  const [syncToast, setSyncToast] = useState(false);

  // Auto-save settings whenever they change
  useEffect(() => {
    const settings = {
      principal,
      contributionAmount,
      contributionFrequency,
      annualRate,
      years,
      compoundingFreq
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
  }, [principal, contributionAmount, contributionFrequency, annualRate, years, compoundingFreq]);

  const handleReset = () => {
    if (window.confirm("Reset calculator to default values?")) {
      localStorage.removeItem(STORAGE_KEY);
      setPrincipal(totalActualInvested || 10000);
      setContributionAmount(suggestedMonthlyContribution);
      setContributionFrequency('monthly');
      setAnnualRate(8);
      setYears(10);
      setCompoundingFreq(12);
    }
  };

  const handleSync = () => {
    setPrincipal(totalActualInvested);
    setContributionAmount(suggestedMonthlyContribution);
    setSyncToast(true);
    setTimeout(() => setSyncToast(false), 3000);
  };

  const projectionData = useMemo(() => {
    const data = [];
    let currentBalance = principal;
    let totalInvested = principal;

    const isDailyCompounding = compoundingFreq === 365;
    const ratePerDay = (annualRate / 100) / 365;
    const ratePerMonth = (annualRate / 100) / 12;

    // Start at Year 0
    data.push({
      year: 0,
      balance: Math.round(currentBalance),
      invested: Math.round(totalInvested),
      interest: 0
    });

    for (let year = 1; year <= years; year++) {
      for (let month = 1; month <= 12; month++) {
        // Handle Contribution
        if (contributionFrequency === 'daily') {
          const monthlyCont = contributionAmount * 30.44;
          currentBalance += monthlyCont;
          totalInvested += monthlyCont;
        } else {
          currentBalance += contributionAmount;
          totalInvested += contributionAmount;
        }

        // Handle Compounding
        if (isDailyCompounding) {
          currentBalance *= Math.pow(1 + ratePerDay, 30.44);
        } else {
          currentBalance *= (1 + ratePerMonth);
        }
      }

      data.push({
        year,
        balance: Math.round(currentBalance),
        invested: Math.round(totalInvested),
        interest: Math.round(currentBalance - totalInvested)
      });
    }
    return data;
  }, [principal, contributionAmount, contributionFrequency, annualRate, years, compoundingFreq]);

  const results = projectionData[projectionData.length - 1];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-teal-100 dark:bg-teal-900/30 rounded-xl">
