                <div className="flex justify-between items-center px-1">
                  <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.monthlyContribution}</label>
                  {historicalMonthlyAverage > 0 && (
                    <button 
                      onClick={handleUseAverage}
                      className="flex items-center gap-1 text-[9px] font-black text-indigo-500 hover:text-indigo-600 uppercase tracking-tighter transition-colors"
                    >
                      <Zap className="w-2.5 h-2.5" /> Use Avg ({formatCurrency(historicalMonthlyAverage)})
                    </button>
                  )}
                </div>
                <div className="flex gap-2">
                  <div className="relative group flex-grow">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-xs font-black text-slate-300 group-focus-within:text-indigo-500 transition-colors">{formatCurrency(0).replace(/[0.,\s]/g, '')}</div>
                    <input 
                      type="number" 
                      value={contributionAmount || ''} 
                      onChange={e => setContributionAmount(Number(e.target.value))}
                      className="w-full pl-11 pr-4 py-3.5 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-950 text-slate-800 dark:text-slate-100 font-black focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
                    />
                  </div>
                  <select 
                    value={contributionFrequency} 
                    onChange={e => setContributionFrequency(e.target.value as 'daily' | 'monthly')}
                    className="px-3 py-3.5 rounded-2xl border border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-indigo-500 transition-all cursor-pointer"
                  >
                    <option value="daily">{t.daily}</option>
                    <option value="monthly">{t.monthly}</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1">{t.annualRate}</label>
