import { Transaction, MonthlyBudget, Bill } from '../types';

const API_URL = 'https://script.google.com/macros/s/AKfycbxTM7V5p8FiW10QC0K550CTJ6V8tSKretm--imdvbf9ChGpuTq3h4ljvP8bBSUOTfye0g/exec';
const LOCAL_STORAGE_KEY = 'finance_tracker_v3_local_data';
const BUDGET_KEY = 'finance_tracker_v3_budgets';
const BILLS_KEY = 'finance_tracker_v3_bills';

export const storageService = {
  async fetchTransactions(): Promise<Transaction[]> {
    try {
      const response = await fetch(API_URL);
      const data = await response.json();
      if (data.records) {
        // Update local cache for offline/fallback use
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data.records));
        return data.records;
      }
    } catch (error) {
      console.error("Failed to fetch from Google Sheets, using local storage:", error);
    }
    const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
    return localData ? JSON.parse(localData) : [];
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    try {
      const payload = {
        action: 'create',
        ...transaction,
        id: transaction.id || crypto.randomUUID()
      };

      // We use standard fetch. Google Apps Script requires CORS headers on the server side
      // for reading responses. If CORS is not enabled on GAS, we use no-cors.
      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors', 
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      // Update local storage to keep them in sync
      const localData = await this.fetchTransactions();
      localData.push(payload);
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(localData));
      return true;
    } catch (error) {
      console.error("Failed to add to Google Sheets:", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    try {
      const payload = {
        action: 'update',
        id,
        ...transaction
      };

      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      const localData = await this.fetchTransactions();
      const index = localData.findIndex(tx => tx.id === id);
      if (index !== -1) {
        localData[index] = { ...transaction, id };
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(localData));
      }
      return true;
    } catch (error) {
      console.error("Failed to update in Google Sheets:", error);
      return false;
    }
  },

  async saveAllTransactions(transactions: Transaction[]): Promise<boolean> {
    // This is the primary backup method called by App.tsx. 
    // It sends the entire recalculated chain to the backend.
    try {
      const payload = {
        action: 'sync', // Assuming the GAS backend handles a full sync/overwrite
        records: transactions
      };

      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(transactions));
      return true;
    } catch (error) {
      console.error("Failed to sync with Google Sheets:", error);
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(transactions));
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    try {
      const payload = {
        action: 'delete',
        id
      };

      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      const localData = await this.fetchTransactions();
      const filtered = localData.filter(tx => tx.id !== id);
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(filtered));
      return true;
    } catch (error) {
      console.error("Failed to delete from Google Sheets:", error);
      return false;
    }
  },

  async fetchBudgets(): Promise<MonthlyBudget[]> {
    const data = localStorage.getItem(BUDGET_KEY);
    return data ? JSON.parse(data) : [];
  },

  async saveBudget(month: string, limits: MonthlyBudget['limits']): Promise<boolean> {
    const budgets = await this.fetchBudgets();
    const index = budgets.findIndex(b => b.month === month);
    if (index !== -1) {
      budgets[index].limits = limits;
    } else {
      budgets.push({ month, limits });
    }
    localStorage.setItem(BUDGET_KEY, JSON.stringify(budgets));
    return true;
  },

  async fetchBills(): Promise<Bill[]> {
    const data = localStorage.getItem(BILLS_KEY);
    return data ? JSON.parse(data) : [];
  },

  async saveBill(bill: Bill): Promise<boolean> {
    const bills = await this.fetchBills();
    const index = bills.findIndex(b => b.id === bill.id);
    if (index !== -1) {
      bills[index] = bill;
    } else {
      bills.push(bill);
    }
    localStorage.setItem(BILLS_KEY, JSON.stringify(bills));
    return true;
  },

  async deleteBill(id: string): Promise<boolean> {
    const bills = await this.fetchBills();
    const filtered = bills.filter(b => b.id !== id);
    localStorage.setItem(BILLS_KEY, JSON.stringify(filtered));
    return true;
  }
};

