To fix the data synchronization issue, you need to update both the **Google Apps Script (Backend)** and the **Storage Service (Frontend)**. The reason you aren't seeing data is likely because the backend script provided in the previous step was missing the new fields (Fuel, Bike Repair, etc.) and had an outdated mapping for the columns.

### 1. Update your Google Apps Script
Copy and paste this updated code into your **Google Apps Script Editor**, then **Deploy as a new version** (Web App). Ensure "Access" is set to "Anyone".

```javascript
/**
 * Personal Finance Tracker - UPDATED Google Apps Script Backend
 */

const SHEET_NAME = 'Transactions';

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    // Header row with all requested fields
    sheet.appendRow([
      'ID', 'Date', 'Month', 'Brought Forward', 'Cash Received', 
      'Groceries', 'Vegetables', 'Fish & Egg', 'Chicken', 'Fuel', 
      'Parcel', 'Bike Repair', 'House Rent', 'Electricity', 'Water Bill', 
      'Travel', 'Compound Investment', 'Others', 'Total Expenses', 
      'Total Balance', 'Timestamp'
    ]);
    sheet.setFrozenRows(1);
  }
}

function doPost(e) {
  let data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return createJsonResponse({ status: 'error', message: 'Invalid JSON' });
  }

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) { setup(); sheet = ss.getSheetByName(SHEET_NAME); }

  const action = data.action;

  // Handle Full Sync (The primary method used by the App)
  if (action === 'sync') {
    const records = data.records;
    if (!Array.isArray(records)) return createJsonResponse({ status: 'error' });

    // Clear existing data (except headers)
    if (sheet.getLastRow() > 1) {
      sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
    }

    // Batch append
    const rows = records.map(tx => [
      tx.id || Utilities.getUuid(), tx.date, tx.month, tx.broughtForward, tx.dailyCash,
      tx.groceries, tx.vegetables, tx.fishEgg, tx.chicken, tx.fuel,
      tx.parcel, tx.bikeRepair, tx.houseRent, tx.electricity, tx.water,
      tx.travel, tx.compoundInvestment, tx.others, tx.totalExpenses, tx.totalBalance, tx.timestamp
    ]);

    if (rows.length > 0) {
      sheet.getRange(2, 1, rows.length, rows[0].length).setValues(rows);
    }
    return createJsonResponse({ status: 'success', synced: rows.length });
  }

  return createJsonResponse({ status: 'error', message: 'Unknown action' });
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) { setup(); return createJsonResponse({ records: [] }); }

  const values = sheet.getDataRange().getValues();
  if (values.length <= 1) return createJsonResponse({ records: [] });

  const headers = values[0];
  const records = [];

  // Map spreadsheet headers to JSON keys used in the App
  const keyMap = {
    'ID': 'id', 'Date': 'date', 'Month': 'month', 'Brought Forward': 'broughtForward',
    'Cash Received': 'dailyCash', 'Groceries': 'groceries', 'Vegetables': 'vegetables',
    'Fish & Egg': 'fishEgg', 'Chicken': 'chicken', 'Fuel': 'fuel', 'Parcel': 'parcel',
    'Bike Repair': 'bikeRepair', 'House Rent': 'houseRent', 'Electricity': 'electricity',
    'Water Bill': 'water', 'Travel': 'travel', 'Compound Investment': 'compoundInvestment',
    'Others': 'others', 'Total Expenses': 'totalExpenses', 'Total Balance': 'totalBalance',
    'Timestamp': 'timestamp'
  };

  for (let i = 1; i < values.length; i++) {
    const record = {};
    headers.forEach((header, index) => {
      const key = keyMap[header.toString().trim()] || header.toString().toLowerCase().replace(/\s+/g, '');
      let val = values[i][index];

      // Clean data types
      if ((key === 'date') && val instanceof Date) {
        val = Utilities.formatDate(val, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
      }
      if (typeof val === 'number' || (!isNaN(val) && val !== "")) {
        const numericFields = ['broughtForward', 'dailyCash', 'groceries', 'vegetables', 'fishEgg', 'chicken', 'fuel', 'parcel', 'bikeRepair', 'houseRent', 'electricity', 'water', 'travel', 'compoundInvestment', 'others', 'totalExpenses', 'totalBalance'];
        if (numericFields.includes(key)) val = Number(val);
      }
      record[key] = val;
    });
    records.push(record);
  }

  return createJsonResponse({ records });
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON)
    .addHeader("Access-Control-Allow-Origin", "*");
}
```

### 2. Frontend Changes
The following update to `services/googleSheets.ts` ensures the `saveAllTransactions` method (which acts as your backup) sends all 21 fields correctly.

